1	import { describe, it, before, after } from 'node:test';
2	import assert from 'node:assert/strict';
3	import { createServer } from 'node:http';
4	import WebSocket from 'ws';
5	import { initWs, broadcast, closeWs } from '../ws/broadcaster.js';
6	
7	// ── Helpers ───────────────────────────────────────────────────────────────────
8	
9	function startWsServer(opts = {}) {
10	  return new Promise((resolve) => {
11	    const httpServer = createServer();
12	    initWs(httpServer, opts);
13	    httpServer.listen(0, () => {
14	      const { port } = httpServer.address();
15	      resolve({ httpServer, wsUrl: `ws://localhost:${port}` });
16	    });
17	  });
18	}
19	
20	async function stopWsServer(httpServer) {
21	  await closeWs();
22	  await new Promise((resolve) => httpServer.close(resolve));
23	}
24	
25	function connectClient(wsUrl) {
26	  return new Promise((resolve, reject) => {
27	    const ws = new WebSocket(wsUrl);
28	    ws.once('open', () => resolve(ws));
29	    ws.once('error', reject);
30	  });
31	}
32	
33	function waitForMessage(ws) {
34	  return new Promise((resolve) => {
35	    ws.once('message', (data) => resolve(JSON.parse(data.toString())));
36	  });
37	}
38	
39	function closeClient(ws) {
40	  return new Promise((resolve) => {
41	    if (ws.readyState === WebSocket.CLOSED) return resolve();
42	    ws.once('close', resolve);
43	    ws.close();
44	  });
45	}
46	
47	function withTimeout(promise, ms) {
48	  return Promise.race([
49	    promise,
50	    new Promise((_, reject) =>
51	      setTimeout(() => reject(new Error(`Timed out after ${ms}ms`)), ms)
52	    ),
53	  ]);
54	}
55	
56	// ── Subtask 1: WebSocket server setup and client connection ───────────────────
57	
58	describe('WebSocket server setup and client connection', () => {
59	  let httpServer, wsUrl;
60	
61	  before(async () => {
62	    ({ httpServer, wsUrl } = await startWsServer());
63	  });
64	
65	  after(async () => {
66	    await stopWsServer(httpServer);
67	  });
68	
69	  it('initWs and broadcast are exported functions', () => {
70	    assert.strictEqual(typeof initWs, 'function');
71	    assert.strictEqual(typeof broadcast, 'function');
72	  });
73	
74	  it('a client can connect successfully', async () => {
75	    const ws = await connectClient(wsUrl);
76	    assert.strictEqual(ws.readyState, WebSocket.OPEN);
77	    await closeClient(ws);
78	  });
79	
80	  it('multiple clients can connect simultaneously', async () => {
81	    const clients = await Promise.all([
82	      connectClient(wsUrl),
83	      connectClient(wsUrl),
84	      connectClient(wsUrl),
85	    ]);
86	    for (const ws of clients) {
